# pink_skin :: lift expired mute restrictions
db = get_service('group_db')
tg = get_service('telegram_bot')
rows = db.execute_query(
    "SELECT id, chat_id, user_id FROM restrictions "
    "WHERE active AND action='mute' AND until_ts IS NOT NULL AND until_ts <= now()")
lifted = 0
for r in rows:
    try:
        tg.call_api('restrictChatMember', {
            'chat_id': int(r['chat_id']), 'user_id': int(r['user_id']),
            'permissions': {
                'can_send_messages': True, 'can_send_media_messages': True,
                'can_send_other_messages': True, 'can_add_web_page_previews': True,
            },
        })
    except Exception:
        pass
    db.execute_update("UPDATE restrictions SET active=FALSE WHERE id=%(i)s", {'i': r['id']})
    lifted += 1
result = 'lifted %d restriction(s)' % lifted
